def merge(defaults, file_cfg, env_cfg, flags):
    out = dict(defaults)
    for layer in (file_cfg, env_cfg, flags):
        for k, v in layer.items():
            if v is not None:
                out[k] = v
    return out

print(merge({"log_level": "INFO"}, {"log_level": "WARNING"}, {"log_level": "DEBUG"}, {"log_level": "ERROR"}))
print(merge({"log_level": "INFO"}, {}, {"log_level": "DEBUG"}, {"log_level": None}))

def validate_config(cfg: dict) -> None:
    for key in ("log_level", "data_dir"):
        if not cfg.get(key):
            raise RuntimeError(f"missing required config key: {key}")

validate_config({"log_level": "INFO", "data_dir": "/tmp/data"})
print("ok")
